const input = $input.first().json;
const body = input.body || input;
const headers = input.headers || {};
const opportunity = body.opportunity || {};
const context = body.context || {};
const contact = context.contact || {};
const object = context.object || {};
const channel = body.channel || 'email';
const naam = contact.name || 'daar';
const adres = [object.address, object.city].filter(Boolean).join(', ') || 'dit object';
const reason = context.reason || opportunity.reason || '';
const webhookSecret = headers['x-webhook-secret'] || headers['X-Webhook-Secret'] || '';
let draftText;
if (channel === 'whatsapp') {
  draftText = `Hallo ${naam}, ik zag een woning voorbij komen die mogelijk goed aansluit op je zoekprofiel: ${adres}. ${reason ? `De aanleiding: ${reason}. ` : ''}Zal ik even met je meekijken of dit interessant voor je is?`;
} else {
  draftText = `Beste ${naam},\n\nIk zag een woning voorbij komen die mogelijk goed aansluit op je zoekprofiel: ${adres}.\n\nWaarom ik aan je dacht:\n${reason || '- passend bij het zoekprofiel'}\n\nAls je wilt kijk ik graag even persoonlijk met je mee of dit object de moeite waard is.\n\nMet vriendelijke groet,\nDe Vree Makelaardij`;
}
return [{ json: { opportunityId: opportunity.id, channel, draftText, webhookSecret } }];
